"use strict";(self.webpackChunkshareme=self.webpackChunkshareme||[]).push([["391"],{54755(n){n.exports=JSON.parse('{"version":{"pluginId":"inverter","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/shareme/inverter/intro","label":"Kho t\xe0i li\u1EC7u cho bi\u1EBFn t\u1EA7n","docId":"intro","unlisted":false},{"type":"category","label":"Mitsubishi","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/shareme/inverter/mitsubishi/e720-mitsubishi","label":"E720","docId":"mitsubishi/e720-mitsubishi","unlisted":false},{"type":"link","href":"/shareme/inverter/mitsubishi/error-codes-mitsubishi","label":"B\u1EA3ng m\xe3 l\u1ED7i & Kh\u1EAFc ph\u1EE5c","docId":"mitsubishi/error-codes-mitsubishi","unlisted":false}],"href":"/shareme/inverter/category/mitsubishi"},{"type":"category","label":"OMRON","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/shareme/inverter/omron/mx2-omron","label":"3G3MX2","docId":"omron/mx2-omron","unlisted":false},{"type":"link","href":"/shareme/inverter/omron/jx-omron","label":"3G3JX","docId":"omron/jx-omron","unlisted":false},{"type":"link","href":"/shareme/inverter/omron/error-codes-omron","label":"B\u1EA3ng m\xe3 l\u1ED7i & Kh\u1EAFc ph\u1EE5c","docId":"omron/error-codes-omron","unlisted":false}],"href":"/shareme/inverter/category/omron"},{"type":"category","label":"WECON","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/shareme/inverter/wecon/wecon-manual","label":"H\u01B0\u1EDBng d\u1EABn s\u1EED d\u1EE5ng WECON VM","docId":"wecon/wecon-manual","unlisted":false},{"type":"link","href":"/shareme/inverter/wecon/parameter-configuration-wecon","label":"B\u1EA3ng tham s\u1ED1 c\xe0i \u0111\u1EB7t (F0 - FD)","docId":"wecon/parameter-configuration-wecon","unlisted":false},{"type":"link","href":"/shareme/inverter/wecon/error-codes-wecon","label":"B\u1EA3ng m\xe3 l\u1ED7i & Kh\u1EAFc ph\u1EE5c (ERR02-22)","docId":"wecon/error-codes-wecon","unlisted":false},{"type":"link","href":"/shareme/inverter/wecon/registers-rs485-wecon","label":"Truy\u1EC1n th\xf4ng Modbus RS-485","docId":"wecon/registers-rs485-wecon","unlisted":false}],"href":"/shareme/inverter/category/wecon"}]},"docs":{"intro":{"id":"intro","title":"Kho t\xe0i li\u1EC7u cho bi\u1EBFn t\u1EA7n","description":"\u0110ang c\u1EADp nh\u1EADt...","sidebar":"tutorialSidebar"},"mitsubishi/e720-mitsubishi":{"id":"mitsubishi/e720-mitsubishi","title":"T\u1ED5ng h\u1EE3p l\u1EC7nh v\xe0 tham s\u1ED1 E720 Mitsubishi","description":"T\xe0i li\u1EC7u t\u1ED5ng h\u1EE3p chi ti\u1EBFt c\xe1c m\xe3 l\u1EC7nh v\xe0 d\u1EA3i c\xe0i \u0111\u1EB7t tham s\u1ED1 c\u1EE7a d\xf2ng bi\u1EBFn t\u1EA7n Mitsubishi FR-E720 (FR-E700 Series). D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EA3ng tra c\u1EE9u nhanh k\xe8m gi\u1EA3i th\xedch chi ti\u1EBFt d\u1EA3i gi\xe1 tr\u1ECB \u0111\u1EC3 thu\u1EADn ti\u1EC7n cho qu\xe1 tr\xecnh c\u1EA5u h\xecnh v\xe0 v\u1EADn h\xe0nh th\u1EF1c t\u1EBF.","sidebar":"tutorialSidebar"},"mitsubishi/error-codes-mitsubishi":{"id":"mitsubishi/error-codes-mitsubishi","title":"B\u1EA3ng m\xe3 l\u1ED7i bi\u1EBFn t\u1EA7n Mitsubishi v\xe0 c\xe1ch kh\u1EAFc ph\u1EE5c","description":"Bi\u1EBFn t\u1EA7n Mitsubishi Electric (c\xe1c d\xf2ng FR-D700, FR-E700, FR-A800 Series) \u0111\u01B0\u1EE3c s\u1EED d\u1EE5ng r\u1EA5t ph\u1ED5 bi\u1EBFn trong c\xf4ng nghi\u1EC7p. Khi x\u1EA3y ra s\u1EF1 c\u1ED1, m\xe0n h\xecnh hi\u1EC3n th\u1ECB (PU) c\u1EE7a bi\u1EBFn t\u1EA7n s\u1EBD b\xe1o m\xe3 s\u1EF1 c\u1ED1 b\u1EAFt \u0111\u1EA7u b\u1EB1ng ch\u1EEF E. (Trip). D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EA3ng t\u1ED5ng h\u1EE3p m\xe3 l\u1ED7i ch\xednh x\xe1c t\u1EEB t\xe0i li\u1EC7u k\u1EF9 thu\u1EADt c\u1EE7a h\xe3ng, nguy\xean nh\xe2n v\xe0 c\xe1c b\u01B0\u1EDBc kh\u1EAFc ph\u1EE5c s\u1EF1 c\u1ED1.","sidebar":"tutorialSidebar"},"omron/error-codes-omron":{"id":"omron/error-codes-omron","title":"B\u1EA3ng m\xe3 l\u1ED7i bi\u1EBFn t\u1EA7n Omron v\xe0 c\xe1ch kh\u1EAFc ph\u1EE5c","description":"Trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh, bi\u1EBFn t\u1EA7n OMRON (MX2, JX, RX Series) c\xf3 th\u1EC3 g\u1EB7p s\u1EF1 c\u1ED1 v\xe0 hi\u1EC3n th\u1ECB m\xe3 l\u1ED7i (Trip) tr\xean m\xe0n h\xecnh LED. T\xe0i li\u1EC7u n\xe0y t\u1ED5ng h\u1EE3p chi ti\u1EBFt danh s\xe1ch m\xe3 l\u1ED7i, nguy\xean nh\xe2n ph\u1ED5 bi\u1EBFn v\xe0 c\xe1c b\u01B0\u1EDBc ki\u1EC3m tra, kh\u1EAFc ph\u1EE5c th\u1EF1c t\u1EBF d\xe0nh cho k\u1EF9 s\u01B0 c\u01A1 \u0111i\u1EC7n.","sidebar":"tutorialSidebar"},"omron/jx-omron":{"id":"omron/jx-omron","title":"T\u1ED5ng h\u1EE3p l\u1EC7nh v\xe0 tham s\u1ED1 3G3JX Omron","description":"T\xe0i li\u1EC7u t\u1ED5ng h\u1EE3p chi ti\u1EBFt c\xe1c m\xe3 l\u1EC7nh v\xe0 d\u1EA3i c\xe0i \u0111\u1EB7t tham s\u1ED1 c\u1EE7a d\xf2ng bi\u1EBFn t\u1EA7n Omron 3G3JX (JX Series) - d\xf2ng bi\u1EBFn t\u1EA7n c\u01A1 b\u1EA3n, nh\u1ECF g\u1ECDn v\xe0 ti\u1EBFt ki\u1EC7m chi ph\xed c\u1EE7a h\xe3ng OMRON. D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EA3ng tra c\u1EE9u nhanh k\xe8m gi\u1EA3i th\xedch chi ti\u1EBFt d\u1EA3i gi\xe1 tr\u1ECB ph\u1EE5c v\u1EE5 thi\u1EBFt k\u1EBF, \u0111\u1EA5u n\u1ED1i v\xe0 c\u1EA5u h\xecnh t\u1EE7 \u0111i\u1EC7n.","sidebar":"tutorialSidebar"},"omron/mx2-omron":{"id":"omron/mx2-omron","title":"T\u1ED5ng h\u1EE3p l\u1EC7nh v\xe0 tham s\u1ED1 3G3MX2 Omron","description":"T\xe0i li\u1EC7u t\u1ED5ng h\u1EE3p chi ti\u1EBFt c\xe1c m\xe3 l\u1EC7nh v\xe0 d\u1EA3i c\xe0i \u0111\u1EB7t tham s\u1ED1 c\u1EE7a d\xf2ng bi\u1EBFn t\u1EA7n Omron 3G3MX2 (MX2 Series). D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EA3ng tra c\u1EE9u nhanh k\xe8m gi\u1EA3i th\xedch chi ti\u1EBFt d\u1EA3i gi\xe1 tr\u1ECB gi\xfap \xedch cho qu\xe1 tr\xecnh thi\u1EBFt k\u1EBF t\u1EE7 \u0111i\u1EC7n, \u0111\u1EA5u n\u1ED1i v\xe0 c\u1EA5u h\xecnh th\u1EF1c t\u1EBF.","sidebar":"tutorialSidebar"},"wecon/error-codes-wecon":{"id":"wecon/error-codes-wecon","title":"B\u1EA3ng M\xe3 L\u1ED7i Bi\u1EBFn T\u1EA7n WECON VM V\xe0 H\u01B0\u1EDBng D\u1EABn X\u1EED L\xfd S\u1EF1 C\u1ED1 (User Manual V2.0)","description":"Khi x\u1EA3y ra s\u1EF1 c\u1ED1 trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh, bi\u1EBFn t\u1EA7n WECON VM Series s\u1EBD ng\u1EAFt ng\xf5 ra \u0111\u1EC3 b\u1EA3o v\u1EC7 thi\u1EBFt b\u1ECB v\xe0 hi\u1EC3n th\u1ECB m\xe3 l\u1ED7i d\u1EA1ng ERRXX tr\xean b\xe0n ph\xedm (\u0111\u1ED3ng th\u1EDDi \u0111\xe8n ALARM nh\u1EA5p nh\xe1y).","sidebar":"tutorialSidebar"},"wecon/parameter-configuration-wecon":{"id":"wecon/parameter-configuration-wecon","title":"B\u1EA3ng M\xe3 Tham S\u1ED1 C\xe0i \u0110\u1EB7t Chi Ti\u1EBFt Bi\u1EBFn T\u1EA7n WECON VM (Function Codes F0 - FD)","description":"T\xe0i li\u1EC7u n\xe0y t\u1ED5ng h\u1EE3p to\xe0n b\u1ED9 b\u1EA3ng m\xe3 tham s\u1ED1 ch\u1EE9c n\u0103ng (Function Codes) c\u1EE7a d\xf2ng bi\u1EBFn t\u1EA7n WECON VM Series d\u1EF1a tr\xean s\u1ED5 tay h\u01B0\u1EDBng d\u1EABn ch\xednh th\u1EE9c phi\xean b\u1EA3n V2.0 (20251203).","sidebar":"tutorialSidebar"},"wecon/registers-rs485-wecon":{"id":"wecon/registers-rs485-wecon","title":"B\u1EA3n \u0110\u1ED3 Thanh Ghi & H\u01B0\u1EDBng D\u1EABn Truy\u1EC1n Th\xf4ng RS-485 Modbus RTU Bi\u1EBFn T\u1EA7n WECON VM","description":"Bi\u1EBFn t\u1EA7n WECON VM Series t\xedch h\u1EE3p s\u1EB5n c\u1ED5ng truy\u1EC1n th\xf4ng n\u1ED1i ti\u1EBFp RS-485 (h\u1ED7 tr\u1EE3 giao th\u1EE9c Modbus RTU chu\u1EA9n c\xf4ng nghi\u1EC7p). T\xednh n\u0103ng n\xe0y cho ph\xe9p \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung bi\u1EBFn t\u1EA7n t\u1EEB h\u1EC7 th\u1ED1ng PLC (Siemens, Mitsubishi, Omron, WECON...) ho\u1EB7c m\xe0n h\xecnh HMI/m\xe1y t\xednh SCADA \u0111\u1EC3 \u0111\u1ECDc/ghi l\u1EC7nh v\u1EADn h\xe0nh, gi\xe1m s\xe1t th\xf4ng s\u1ED1 th\u1EDDi gian th\u1EF1c v\xe0 c\xe0i \u0111\u1EB7t tham s\u1ED1 t\u1EEB xa.","sidebar":"tutorialSidebar"},"wecon/wecon-manual":{"id":"wecon/wecon-manual","title":"S\u1ED5 Tay H\u01B0\u1EDBng D\u1EABn V\u1EADn H\xe0nh Bi\u1EBFn T\u1EA7n WECON VM Series (User Manual V2.0)","description":"Bi\u1EBFn t\u1EA7n WECON VM Series AC Drive (Phi\xean b\u1EA3n t\xe0i li\u1EC7u chu\u1EA9n V2.0) l\xe0 d\xf2ng bi\u1EBFn t\u1EA7n \u0111a n\u0103ng cao c\u1EA5p c\u1EE7a h\xe3ng WECON, h\u1ED7 tr\u1EE3 c\xf4ng su\u1EA5t t\u1EEB 0.4 kW \u0111\u1EBFn 1000.0 kW (Ngu\u1ED3n v\xe0o 1 pha 220V / 3 pha 380V). \u0110i\u1EC3m \u0111\u1EB7c bi\u1EC7t n\u1ED5i b\u1EADt c\u1EE7a d\xf2ng WECON VM l\xe0 kh\u1EA3 n\u0103ng v\u1EADn h\xe0nh linh ho\u1EA1t cho c\u1EA3 \u0110\u1ED9ng c\u01A1 3 pha v\xe0 \u0110\u1ED9ng c\u01A1 1 pha (Single-Phase AC Motor), t\xedch h\u1EE3p s\u1EB5n b\u1ED9 \u0111i\u1EC1u khi\u1EC3n Vector, phanh DC, truy\u1EC1n th\xf4ng Modbus RTU v\xe0 b\u1ED9 PLC n\u1ED9i h\xe0m 16 c\u1EA5p t\u1ED1c \u0111\u1ED9.","sidebar":"tutorialSidebar"}}}}')}}]);